final:
module top_module(
	Ra,
	Rb,
	aluOut,
	aluControl,
	IR
);input [15:0] Ra;
input [15:0] Rb;
input [5:0] IR;
input [1:0] aluControl;
output [15:0] aluOut;

wire [15:0] alt_input_a;
wire [15:0] input_b;
wire [15:0] imm;

assign imm = { {12{IR[4]}}, IR[4:0] };

assign input_b = IR[5] ? imm : Rb;
assign alt_input_a = Ra;

assign aluOut = (aluControl == 0) ? alt_input_a :
					 (aluControl == 1) ? alt_input_a + input_b :
					 (aluControl == 2) ? alt_input_a & input_b :
					 ~alt_input_a;

endmodule
